import{_ as t,o as r,c as e,a2 as i}from"./chunks/framework.VxKNwi4m.js";const b=JSON.parse('{"title":"IBS 워크스페이스(Workspace) 시작하기","description":"","frontmatter":{},"headers":[],"relativePath":"intro/getting-started.md","filePath":"intro/getting-started.md","lastUpdated":1783560819000}'),l={name:"intro/getting-started.md"};function o(n,a,s,h,d,u){return r(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="ibs-워크스페이스-workspace-시작하기" tabindex="-1">IBS 워크스페이스(Workspace) 시작하기 <a class="header-anchor" href="#ibs-워크스페이스-workspace-시작하기" aria-label="Permalink to &quot;IBS 워크스페이스(Workspace) 시작하기&quot;">​</a></h1><blockquote><p><strong>IBS 워크스페이스</strong>는 부동산 개발 프로젝트의 전 과정(Life-cycle)을 &#39;업무(Issue)&#39; 단위로 통합 관리하고 공유하는 사용자 친화적 업무 환경을 제공합니다. 이 문서는 신규 사용자가 시스템에 접속하여 팀 워크스페이스를 구성하고 첫 업무를 시작하는 과정을 안내합니다.</p></blockquote><h2 id="이-문서의-대상" tabindex="-1">이 문서의 대상 <a class="header-anchor" href="#이-문서의-대상" aria-label="Permalink to &quot;이 문서의 대상&quot;">​</a></h2><ul><li><strong>사업관리/현장 팀원</strong>: 부지 매입, 인허가 및 공정 관리를 수행하는 실무자</li><li><strong>분양/영업 담당자</strong>: 고객 응대, 계약 및 수납 업무를 수행하는 담당자</li><li><strong>재무/자금 팀원</strong>: 사업 예산 관리 및 수지 분석을 담당하는 전문가</li><li><strong>의사결정자</strong>: 실시간 보고서를 통해 사업 현황을 파악하는 경영진</li></ul><h2 id="ibs-워크스페이스의-업무-흐름" tabindex="-1">IBS 워크스페이스의 업무 흐름 <a class="header-anchor" href="#ibs-워크스페이스의-업무-흐름" aria-label="Permalink to &quot;IBS 워크스페이스의 업무 흐름&quot;">​</a></h2><p>IBS는 팀원들이 하나의 공간에서 유기적으로 협력하도록 설계되었습니다.</p><ol><li><strong>워크스페이스 구축</strong>: 프로젝트 마스터 정보 및 동·호수 등 기초 데이터 설정</li><li><strong>협업 엔진 가동</strong>: &#39;업무(Issue)&#39; 메뉴를 통한 이슈 발행 및 담당자 지정</li><li><strong>실무 데이터 축적</strong>: 부지 매입, 분양 계약 및 수납 데이터의 실시간 입력</li><li><strong>자금 흐름 동기화</strong>: 사업비 집행 및 수납금의 회계 자동 전산화</li><li><strong>통찰력 확보</strong>: 통합 리포트를 통한 실시간 사업 수지 및 리스크 파악</li></ol><h2 id="시스템-접속-및-가입" tabindex="-1">시스템 접속 및 가입 <a class="header-anchor" href="#시스템-접속-및-가입" aria-label="Permalink to &quot;시스템 접속 및 가입&quot;">​</a></h2><h3 id="접속-주소" tabindex="-1">접속 주소 <a class="header-anchor" href="#접속-주소" aria-label="Permalink to &quot;접속 주소&quot;">​</a></h3><blockquote><p><strong><a href="https://ibs.dyibs.com" target="_blank" rel="noreferrer">https://ibs.dyibs.com</a></strong></p></blockquote><h3 id="계정-생성-및-시작하기" tabindex="-1">계정 생성 및 시작하기 <a class="header-anchor" href="#계정-생성-및-시작하기" aria-label="Permalink to &quot;계정 생성 및 시작하기&quot;">​</a></h3><h4 id="_1-회원-가입-직원용" tabindex="-1">1. 회원 가입 (직원용) <a class="header-anchor" href="#_1-회원-가입-직원용" aria-label="Permalink to &quot;1. 회원 가입 (직원용)&quot;">​</a></h4><ul><li>메인 화면의 가입 링크를 통해 본인의 아이디를 생성합니다.</li><li>가입 시 사내 보안 코드인 **계정 생성코드(<code>dyibs-staff</code>)**를 반드시 입력해야 합니다.</li></ul><h4 id="_2-권한-승인-및-프로젝트-참여" tabindex="-1">2. 권한 승인 및 프로젝트 참여 <a class="header-anchor" href="#_2-권한-승인-및-프로젝트-참여" aria-label="Permalink to &quot;2. 권한 승인 및 프로젝트 참여&quot;">​</a></h4><ul><li>가입 완료 후 시스템 관리자에게 접속하려는 프로젝트(워크스페이스)의 참여 승인을 요청합니다.</li><li>승인이 완료되면 사이드바에서 해당 프로젝트의 모든 메뉴가 활성화됩니다.</li></ul><h2 id="초기-데이터-설정-5단계-onboarding" tabindex="-1">초기 데이터 설정 5단계 (Onboarding) <a class="header-anchor" href="#초기-데이터-설정-5단계-onboarding" aria-label="Permalink to &quot;초기 데이터 설정 5단계 (Onboarding)&quot;">​</a></h2><p>워크스페이스를 처음 시작할 때는 다음 순서로 데이터를 구축하는 것이 효율적입니다.</p><h3 id="_1단계-프로젝트-기본-정보" tabindex="-1">1단계: 프로젝트 기본 정보 <a class="header-anchor" href="#_1단계-프로젝트-기본-정보" aria-label="Permalink to &quot;1단계: 프로젝트 기본 정보&quot;">​</a></h3><ul><li>사업명, 위치, 기간 등 프로젝트의 신원을 정의합니다.</li></ul><h3 id="_2단계-상품-정보-구성-unit" tabindex="-1">2단계: 상품 정보 구성 (Unit) <a class="header-anchor" href="#_2단계-상품-정보-구성-unit" aria-label="Permalink to &quot;2단계: 상품 정보 구성 (Unit)&quot;">​</a></h3><ul><li>분양할 동·호수와 유닛 타입을 일괄 생성하여 &#39;판매 가능한 자산&#39; 상태로 만듭니다.</li></ul><h3 id="_3단계-계약-및-수지-조건-수립" tabindex="-1">3단계: 계약 및 수지 조건 수립 <a class="header-anchor" href="#_3단계-계약-및-수지-조건-수립" aria-label="Permalink to &quot;3단계: 계약 및 수지 조건 수립&quot;">​</a></h3><ul><li>분양 가격표(Price list)와 납부 스케줄(Payment plan)을 설정합니다.</li><li>지출 예산 항목을 구성하여 자금 집행의 기준을 만듭니다.</li></ul><h3 id="_4단계-기존-데이터-이관" tabindex="-1">4단계: 기존 데이터 이관 <a class="header-anchor" href="#_4단계-기존-데이터-이관" aria-label="Permalink to &quot;4단계: 기존 데이터 이관&quot;">​</a></h3><ul><li>이미 진행 중인 토지 매입 현황이나 계약자 목록을 시스템에 입력합니다.</li></ul><h3 id="_5단계-첫-업무-issue-발행" tabindex="-1">5단계: 첫 업무(Issue) 발행 <a class="header-anchor" href="#_5단계-첫-업무-issue-발행" aria-label="Permalink to &quot;5단계: 첫 업무(Issue) 발행&quot;">​</a></h3><ul><li>현재 진행 중인 핵심 과제(예: 인허가 접수 등)를 업무 게시판에 등록하고 팀원을 소환(Watcher)합니다.</li></ul><h2 id="사용자-친화적-기능-활용-팁" tabindex="-1">사용자 친화적 기능 활용 팁 <a class="header-anchor" href="#사용자-친화적-기능-활용-팁" aria-label="Permalink to &quot;사용자 친화적 기능 활용 팁&quot;">​</a></h2><ul><li><strong>프로젝트 전환</strong>: 상단 메뉴를 통해 여러 프로젝트를 원클릭으로 이동할 수 있습니다.</li><li><strong>이슈 알림</strong>: 나에게 할당된 업무나 관심 있는 업무의 변경 사항을 실시간으로 확인합니다.</li><li><strong>다크/라이트 테마</strong>: 사용자 취향에 맞는 테마를 선택하여 눈의 피로도를 조절합니다.</li><li><strong>최근 작업 메뉴</strong>: 최근에 방문했던 메뉴들이 상단에 유지되어 재방문이 편리합니다.</li></ul><h2 id="도움-요청-및-기술-지원" tabindex="-1">도움 요청 및 기술 지원 <a class="header-anchor" href="#도움-요청-및-기술-지원" aria-label="Permalink to &quot;도움 요청 및 기술 지원&quot;">​</a></h2><p>시스템 사용 중 궁금한 점이 생기면 언제든지 문의해 주세요.</p><ul><li><strong>사내 커뮤니티</strong>: <a href="https://ibs.dyibs.com/#/work/project/ibs/boards/1" target="_blank" rel="noreferrer">IBS 기술지원 게시판</a></li><li><strong>관리 부서</strong>: IT·디지털혁신팀</li><li><strong>문의 방법</strong>: 오류 현상의 화면 캡처와 함께 메뉴명을 기재하여 게시판에 등록</li></ul><hr><p><strong>IBS 워크스페이스</strong>는 여러분의 업무가 더 즐겁고 효율적이 되도록 돕는 든든한 공간이 되겠습니다.</p>',34)])])}const g=t(l,[["render",o]]);export{b as __pageData,g as default};
